import { type ExtensionAPI } from "@earendil-works/pi-coding-agent";
import { Container, SelectList, Text, Spacer } from "@earendil-works/pi-tui";
import { readdir, stat } from "node:fs/promises";
import { resolve, join } from "node:path";
import os from "node:os";

export default function (pi: ExtensionAPI) {
  pi.registerCommand("session-import", {
    description: "Browse and import past sessions",
    handler: async (_, ctx) => {
      try {
        const sessionDir = resolve(os.homedir(), ".pi/agent/sessions");

        // Recursively find all .jsonl files with mtime
        async function getFiles(dir: string): Promise<{ path: string; mtime: number }[]> {
          try {
            const entries = await readdir(dir, { withFileTypes: true });
            const results = await Promise.all(
              entries.map(async (res) => {
                const resPath = resolve(dir, res.name);
                if (res.isDirectory()) {
                  return getFiles(resPath);
                } else if (res.name.endsWith(".jsonl")) {
                  const stats = await stat(resPath);
                  return [{ path: resPath, mtime: stats.mtimeMs }];
                }
                return [];
              })
            );
            return results.flat();
          } catch (e) {
            return [];
          }
        }

        const fileEntries = await getFiles(sessionDir);
        fileEntries.sort((a, b) => b.mtime - a.mtime);

        if (fileEntries.length === 0) {
          ctx.ui.notify("No session files found.", "warning");
          return;
        }

        const items = fileEntries.slice(0, 10).map(entry => ({
          value: entry.path,
          label: entry.path.split('/').pop() || entry.path,
          description: entry.path.replace(os.homedir(), "~")
        }));

        const selectedPath = await ctx.ui.custom<string>((tui, theme, _kb, done) => {
          const container = new Container();
          container.addChild(new Text(theme.fg("accent", theme.bold(" Select Session to Import")), 1, 0));
          container.addChild(new Spacer(1));

          // Ensure theme has selectedText and description
          const listTheme = new Proxy(theme, {
            get(target, prop, receiver) {
              if (prop === 'selectedText') {
                return (text: string) => {
                  if (typeof (target as any).selectedText === 'function') {
                    return (target as any).selectedText(text);
                  }
                  return target.bold(target.fg("accent", text));
                };
              }
              if (prop === 'description') {
                if (typeof (target as any).description === 'function') {
                  return (target as any).description.bind(target);
                }
                return (text: string) => target.dim(text);
              }
              return Reflect.get(target, prop, receiver);
            }
          });

          const list = new SelectList(items, Math.min(items.length, 15), listTheme as any);

          list.onSelect = (item) => done(item.value);
          list.onCancel = () => done("");
          container.addChild(list);

          return {
            render: (w) => container.render(w),
            invalidate: () => container.invalidate(),
            handleInput: (data) => {
              list.handleInput(data);
              tui.requestRender();
            },
          };
        }, { overlay: true });

        if (selectedPath) {
          // We notify the user of the command to run. 
          // We can't automatically run /import from inside an extension, 
          // but we can provide the exact path which is now on their screen.
          ctx.ui.notify(`Run: /import ${selectedPath}`, "info");
          ctx.ui.setEditorText(`/import ${selectedPath}`);
        }
      } catch (e) {
        ctx.ui.notify(`Error: ${e instanceof Error ? e.message : String(e)}`, "error");
      }
    },
  });
}
